export type InitialStateType = {
    isAoth: boolean,
    users: any,
}
const initialState: InitialStateType = {
    isAoth: false,
    users: [],
}

const authReducer = (state = initialState) => {

    let copy;
    async function api() {
        //@ts-ignore
        const token = JSON.parse(localStorage.getItem("user")).accessToken;
        if (token === null) {
            return console.log("SVDFSBDFBSD")
        } else {
            const request = await fetch("http://localhost:5000/api/users", {
                headers: {
                    method: "GET",
                    authorisation: token,
                }
            })
            const response = await request.json();
            return response;
        }
    }
    const a = api();
    copy = { ...state, isAoth: true, users: a };
    return copy;
};



export default authReducer;
